{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-citation-ordering-diagnostics-before-artifacts-before-snapshot-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "success",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的进料流股 feed-15 和加热器单元 heater-5 的缺失规格问题生成候选提案：Cold Feed 缺少流量规格，Guard Heater 在出口温度控制模式下缺少出口温度目标。",
      "issues": [
        {
          "title": "Cold Feed 缺少流量规格",
          "description": "诊断指出流股 feed-15 缺少 flow rate specification；该流股当前仅提供 pressure_kpa，缺少可用于求解的流量规格。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "feed-15"
          },
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "Guard Heater 缺少出口温度控制目标",
          "description": "诊断指出单元 heater-5 配置为 outlet_temperature 控制模式，但缺少 outlet temperature target；当前单元配置仅显示 control_mode，没有对应目标参数。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "heater-5"
          },
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Cold Feed 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-15"
          },
          "rationale": "feed-15 被诊断为缺少流量规格；由于当前请求未提供可信的具体流量数值，建议仅添加待确认的规格占位，避免凭空设定工艺条件。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "reason": "STREAM_SPEC_MISSING: Cold Feed is missing flow rate specification.",
                "suggested_source": "user_confirmation"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ],
          "confidence": 0.86
        },
        {
          "action": "candidate_edit",
          "title": "为 Guard Heater 添加出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-5"
          },
          "rationale": "heater-5 当前处于 outlet_temperature 控制模式，诊断明确指出缺少出口温度目标；由于输入中未给出应采用的目标温度，建议仅添加待确认的参数占位。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target": {
                "required": true,
                "reason": "UNIT_PARAMETER_INCOMPLETE: Guard Heater is configured for outlet temperature control but outlet temperature target is missing.",
                "suggested_source": "user_confirmation"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "snapshot-1"
          ],
          "confidence": 0.88
        }
      ]
    }
  ]
}
